(42769, 'zhCN', '在“至暗之夜”第1赛季中不再需要使用英雄曙光纹章。', '曙光英雄', '角色解锁：用英雄曙光纹章交易神话曙光纹章', 67186);
INSERT INTO `battle_pet_species_locale` (`ID`, `locale`, `Description_lang`, `SourceText_lang`, `VerifiedBuild`) VALUES
(5065, 'zhCN', '真正的深渊钓客，由深潜者杰祖亲自认证。', '|cFFFFD200商人出售：|r深潜者图纳基特|n|cFFFFD200地区：|r祖阿曼|n|cFFFFD200价格：|r2400|Hcurrency:3373|h|TInterface\\ICONS\\Item_enchantedpearl.blp:0|t|h|n|n', 67186);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(309753, 'zhCN', '你想测量哪项指标？', '你想测量哪项指标？', 67186),
(303469, 'zhCN', '总算解决掉一个特工。很好。下一个是“非法降雨”。\n\n我们可以从这里进去。', '', 67186),
(295258, 'zhCN', '', '小心，看起来那几个还只是幼崽。', 67186),
(289969, 'zhCN', '我已经在银色盟约手中失去了太多同胞。\n\n他们说那是战争。他们说双方都有伤亡。可我的夺日者从未对达拉然的任何人进行过清洗。\n\n有一个风行者因为清洗城市而得到了应有的报应。而另一个今天就站在我面前。', '', 67186),
(294283, 'zhCN', '我是西塞，丽丽的哥哥。真遗憾没能亲自在那里迎接你。现在是不是所有人都在等我们？\n\n前几天我去武松村筹备节庆，结果发现我们最珍贵的烟花不翼而飞了！我匆忙赶回家寻找，到现在还是毫无线索。时间越来越紧了。看来只能凑合过一场没有烟花的节日了。\n\n<西塞用爪子抹了抹额上的汗珠。>\n\n很荣幸认识你，丽丽的朋友。我们二人已有数年未见，想必有无数冒险经历可以分享——当然，多半是她的精彩故事，而我的平淡无奇。那之后我就从家乡搬到了晨息村。那里风景如画，临湖而居。', '', 67186);
