INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'zhCN', '晦暗虚空核心', '在“至暗之夜”第1赛季团队副本中击败强大的敌人，或完成史诗钥石地下城、丰裕地下堡以及梦魇难度的狩猎，即可将其转化为强大的装备。', 67186),
(3347, 'zhCN', '神话曙光纹章', '用于升级“至暗之夜”第1赛季的神话装备，最多升级至物品等级276-289。\n\n用于制造时，根据品质将制成品的物品等级设定为272-285。\n\n可以从以下活动获得：\n\n- 史诗难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 9级及以上的史诗钥石地下城', 67186),
(3346, 'zhCN', '英雄曙光纹章', '用于升级“至暗之夜”第1赛季的英雄装备，最多升级至物品等级263-276。可以从以下活动获得：\n\n- 英雄难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 4-8级的史诗钥石地下城\n- 地下堡（难度11）\n- 珍宝猎手的奖赏（难度8及以上）\n- 狩猎（梦魇）', 67186),
(3345, 'zhCN', '英雄曙光纹章', '用于升级“至暗之夜”第1赛季的英雄装备，最多升级至物品等级263-276。\n\n用于制造时，根据品质将制成品的物品等级设定为259-272。\n\n可以从以下活动获得：\n\n- 英雄难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 4-8级的史诗钥石地下城\n- 地下堡（难度11）\n- 珍宝猎手的奖赏（难度8及以上）\n- 狩猎（梦魇）', 67186),
(3344, 'zhCN', '勇士曙光纹章', '用于升级“至暗之夜”第1赛季的勇士装备，最多升级至物品等级250-263。可以从以下活动获得：\n\n- 每周户外活动\n- 普通难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 史诗难度的赛季地下城\n- 2-3级的史诗钥石地下城\n- 地下堡（难度7-10）\n- 珍宝猎手的奖赏（难度6-7）\n- 狩猎（梦魇）', 67186),
(3343, 'zhCN', '勇士曙光纹章', '用于升级“至暗之夜”第1赛季的勇士装备，最多升级至物品等级250-263。可以从以下活动获得：\n\n- 每周户外活动\n- 普通难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 史诗难度的赛季地下城\n- 2-3级的史诗钥石地下城\n- 地下堡（难度7-10）\n- 珍宝猎手的奖赏（难度6-7）\n- 狩猎（梦魇）', 67186),
(3342, 'zhCN', '老兵曙光纹章', '用于升级“至暗之夜”第1赛季的老兵装备，最多升级至物品等级237-250。可以从以下活动获得：\n\n- 可重复的户外活动\n- 随机难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 英雄难度的赛季地下城\n- 地下堡（难度5-6）\n- 珍宝猎手的奖赏（难度4-5）\n- 狩猎（困难）', 67186),
(3341, 'zhCN', '老兵曙光纹章', '用于升级“至暗之夜”第1赛季的老兵装备，最多升级至物品等级237-250。\n\n用于制造时，根据品质将制成品的物品等级设定为233-246。\n\n可以从以下活动获得：\n\n- 可重复的户外活动\n- 随机难度的虚影尖塔、梦境裂隙和进军奎尔丹纳斯\n- 英雄难度的赛季地下城\n- 地下堡（难度5-6）\n- 珍宝猎手的奖赏（难度4-5）\n- 狩猎（困难）', 67186),
(3418, 'zhCN', '晦暗虚空核心', '在“至暗之夜”第1赛季团队副本中击败强大的敌人，或完成史诗钥石地下城、丰裕地下堡以及梦魇难度的狩猎，即可将其转化为强大的装备。', 67186),
(3391, 'zhCN', '冒险者曙光纹章', '用于升级“至暗之夜”第1赛季的冒险者装备，最多升级至物品等级224-237。可以从以下活动获得：\n\n- 可重复的户外活动\n- 地下堡（难度4）\n- 狩猎（普通）', 67186),
(3383, 'zhCN', '冒险者曙光纹章', '用于升级“至暗之夜”第1赛季的冒险者装备，最多升级至物品等级224-237。\n\n用于制造时，根据品质将制成品的物品等级设定为220-233。\n\n可以从以下活动获得：\n\n- 可重复的户外活动\n- 地下堡（难度4）\n- 狩猎（普通）', 67186),
