INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'zhCN', '坦克', '$bullet;囤宝狂人在施放|cFF2959D3|Hspell:1235072|h[资源巧用]|h|r期间会从最近的资源堆中收集资源。\n$bullet;接触腐烂的蘑菇会施加|cFF2959D3|Hspell:1234846|h[剧毒孢子]|h|r，阻止其引发|cFF2959D3|Hspell:1245593|h[腐烂爆发]|h|r。\n$bullet;|cFF2959D3|Hspell:1234681|h[贪婪咆哮]|h|r和|cFF2959D3|Hspell:1235125|h[饕餮怒吼]|h|r对所有玩家造成高额伤害。', 67186),
(32669, 'zhCN', '综述', '囤宝狂人会不惜一切代价阻止他的囤宝被盗，在生命值达到90%、60%和30%时施放|cFF2959D3|Hspell:1235072|h[资源巧用]|h|r，强化他的一个技能。\n\n能量达到100时，他会扔出|cFF2959D3|Hspell:1234233|h[腐坏补给]|h|r，使其生长成腐烂的蘑菇，持续12秒。接触后，这些蘑菇会施加|cFF2959D3|Hspell:1234846|h[剧毒孢子]|h|r并被摧毁，阻止|cFF2959D3|Hspell:1245593|h[腐烂爆发]|h|r。', 67186),
(31527, 'zhCN', '违禁的货物', '一批需要避人耳目的货物。可以作为绝佳的掩体。', 67186),
(31282, 'zhCN', '坦克', '$bullet;凯斯媞亚通过|cFF2959D3|Hspell:1230289|h[非法灌注]|h|r使咬咬对玩家怀有敌意。\n$bullet;躲开咬咬的|cFF2959D3|Hspell:1253811|h[邪能飞溅]|h|r。\n$bullet;打断凯斯媞亚的|cFF2959D3|Hspell:1264095|h[镜像]|h|r。', 67186),
(31281, 'zhCN', '治疗者', '$bullet;凯斯媞亚通过|cFF2959D3|Hspell:1230289|h[非法灌注]|h|r使咬咬对玩家怀有敌意。\n$bullet;躲开咬咬的|cFF2959D3|Hspell:1253811|h[邪能飞溅]|h|r。\n$bullet;凯斯媞亚在|cFF2959D3|Hspell:1265412|h[不稳定]|h|r状态下会对所有玩家造成大量伤害。', 67186),
(31280, 'zhCN', '伤害输出者', '$bullet;凯斯媞亚通过|cFF2959D3|Hspell:1230289|h[非法灌注]|h|r使咬咬对玩家怀有敌意。\n$bullet;躲开咬咬的|cFF2959D3|Hspell:1253811|h[邪能飞溅]|h|r。\n$bullet;打断凯斯媞亚的|cFF2959D3|Hspell:1264095|h[镜像]|h|r。', 67186),
(35862, 'zhCN', 'Section 18', '', 67186),
(35353, 'zhCN', '第17部分', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'zhCN', '第17部分', '', 67186),
(34733, 'zhCN', '萨拉塔斯的狡诈', '萨拉塔斯背叛了玩家，撤销了自己的交易，而且每次角色死亡都会让剩余时间减少15秒。', 67186),
(34732, 'zhCN', '强韧', '非首领敌人的生命值提高20%，造成的伤害最多提高20%。', 67186),
(34731, 'zhCN', '残暴', '首领的生命值提高25%，首领及其爪牙造成的伤害最多提高15%。', 67186),
(34730, 'zhCN', '残暴与强韧', '这些词缀会进一步强化史诗钥石地下城中的敌人。一个在史诗等级7激活，另一个在史诗等级10激活，每周轮换。', 67186),
(34727, 'zhCN', '萨拉塔斯的交易：吞噬', '', 67186),
(34725, 'zhCN', '萨拉塔斯的交易：虚缚', '', 67186),
(34722, 'zhCN', '萨拉塔斯的交易：脉冲', '', 67186),
(34720, 'zhCN', '史诗等级6', '$bullet;|cFF2959D3|Hspell:1284818|h[林多尔米的指引]|h|r被移除。\n\n拥有坦克专精的角色可以与时间流传送门附近或史诗钥石地下城终点处的林多尔米交谈，获得|cFF2959D3|Hspell:1295986|h[林多尔米的光辉]|h|r，该效果将继续标记敌方部队。', 67186),
(35809, 'zhCN', 'Section 158', '', 67186),
(35491, 'zhCN', '第69部分', '', 67186),
(35490, 'zhCN', '第70部分', '', 67186),
(35489, 'zhCN', '第76部分', '', 67186),
