INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'zhCN', '你好，虔诚的信徒！\n\n快来领略这片领地的奇迹——这里充盈着无上的丰饶！这股伟力在翻腾，在扩张，万物皆无法束缚其生机！\n\n你对我这尊神格的虔诚，理应得到一份小小的嘉奖。这次，便以此纯粹丰饶作为恩赏！\n\n此外，睿智的信徒，请留意：如熔铸活力在内的某些祭品现在也会在其他商贩处上架。若你的冒险足迹经过祖阿曼深渊附近，或许能与他们不期而遇。\n\n愿你岁岁大丰收。\n\n——钝顿，丰饶之神', 67186);
